from collections import Counter

class Solution:
    def lexSmallestAfterDeletion(self, s):
        n = len(s)
        total = Counter(s)
        best = None
        for mask in range(1, 1 << n):
            kept = [s[i] for i in range(n) if mask & (1 << i)]
            cnt = Counter(kept)
            if all(cnt[ch] >= 1 for ch in total):
                candidate = ''.join(kept)
                if best is None or candidate < best:
                    best = candidate
        return best

