from collections import Counter

class Solution:
    def lexSmallestAfterDeletion(self, s):
        remaining = Counter(s)
        stack = []
        stack_count = Counter()
        for ch in s:
            remaining[ch] -= 1
            while stack and stack[-1] > ch and (remaining[stack[-1]] > 0 or stack_count[stack[-1]] > 1):
                popped = stack.pop()
                stack_count[popped] -= 1
            stack.append(ch)
            stack_count[ch] += 1
        while len(stack) > 1 and stack_count[stack[-1]] > 1:
            stack_count[stack[-1]] -= 1
            stack.pop()
        return ''.join(stack)

