var lexSmallestAfterDeletion = function(s) {
    const remaining = {};
    for (const ch of s) remaining[ch] = (remaining[ch] || 0) + 1;
    const stack = [];
    const stackCount = {};
    for (const ch of s) {
        remaining[ch] -= 1;
        while (stack.length) {
            const top = stack[stack.length - 1];
            if (!(top > ch)) break;
            if (!((remaining[top] || 0) > 0 || (stackCount[top] || 0) > 1)) break;
            stack.pop();
            stackCount[top] -= 1;
        }
        stack.push(ch);
        stackCount[ch] = (stackCount[ch] || 0) + 1;
    }
    while (stack.length > 1 && stackCount[stack[stack.length - 1]] > 1) {
        const top = stack[stack.length - 1];
        stackCount[top] -= 1;
        stack.pop();
    }
    return stack.join('');
};
